Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var sut = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await sut.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.NotFound);
        var sut = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        var handler = new FakeHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // fail the test if it takes longer than 5s
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        var handler = new FakeHandler("fast", HttpStatusCode.OK);
        var sut = new DataFetcher(new HttpClient(handler));

        // Pass TestContext.CancellationToken so the [Timeout] can cancel cooperatively
        var result = await sut.FetchAsync("https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    // Reusable fake HttpMessageHandler — no mocking library needed
    private sealed class FakeHandler(string content, HttpStatusCode status, TimeSpan? delay = null)
        : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay is { } d)
            {
                await Task.Delay(d, cancellationToken);
            }

            return new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cooperative timeout** | `[Timeout(5000)]` + pass `_testContext.CancellationToken` into the method under test |
| **Cancellation** | Create a pre-cancelled `CancellationTokenSource`, assert `TaskCanceledException` |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **HttpClient testing** | Custom `HttpMessageHandler` subclass — no mock framework needed |
| **Sealed class + ctor injection** | `TestContext` injected via constructor, enabling `readonly` fields |

The critical detail: **always flow `TestContext.CancellationToken`** into async calls when using `[Timeout]`. Without it, the timeout fires but the test method keeps running — the timeout becomes uncooperative and may hang until the framework forcibly kills the thread.
